const App = () => {
  const names = 'Half Stack application development'
  const part1 = 'Fundamentals of React'
  const exercises1 = 10
  const part2 = 'Using props tco pass data'
  const exercises2 = 7
  const part3 = 'State of a component'
  const exercises3 = 14
  const text = 'Number of exercises '
  const course = {
    name: 'Half Stack application development',
    parts: [
      {
        name: 'Fundamentals of React',
        exercises: 10,
      },
      {
        name: 'Using props to pass data',
        exercises: 7,
      },
      {
        name: 'State of a component',
        exercises: 14,
      },
    ]
  }
  return (
    <div>
      <Header course={course.name} />
      <Content parts={part1} exercises={exercises1} />
      <Content parts={part2} exercises={exercises2} />
      <Content parts={part3} exercises={exercises3} />
      <Total totalFist={exercises1} />
    </div>
  )
}

const Header = (props) => {
  return (
    <h1>{props.course}</h1>
  )
}


const Content = (props) => {
  return (
    <p>{props.parts} {props.exercises}</p>
  )

}
const Total = (props) => {
  return (
    <p>{props.totalFist} {props.totalSecond} {props.totalThree}</p>
  )
}

export default App
